    <div class="flex items-center justify-between border-b border-gray-200 pb-4 mb-6">
      <div>
        <h1 class="text-xl font-medium tracking-tight text-gray-900" id="board-title">Project Ollie Board</h1>
        <p class="text-xs text-gray-500 mt-1">Real-time collaborative task tracker</p>
