          <h2 class="font-medium text-gray-700 text-xs tracking-wider uppercase">In Progress</h2>
          <span id="inprogress-count" class="bg-gray-200 text-gray-700 text-xs px-2 py-0.5 rounded-full font-medium">0</span>
        </div>
        <div id="inprogress-list" class="space-y-3 flex-grow" ondragover="allowDrop(event)" ondrop="drop(event, 'in-progress')">
          <!-- Tasks inject here -->
        </div>
      </div>

