      <div class="bg-surface-container rounded-xl p-4 flex flex-col min-h-[500px] border border-gray-100">
        <div class="flex items-center justify-between mb-4 px-1">
          <h2 class="font-medium text-gray-700 text-xs tracking-wider uppercase">Done</h2>
          <span id="done-count" class="bg-gray-200 text-gray-700 text-xs px-2 py-0.5 rounded-full font-medium">0</span>
        </div>
        <div id="done-list" class="space-y-3 flex-grow" ondragover="allowDrop(event)" ondrop="drop(event, 'done')">
          <!-- Tasks inject here -->
        </div>
      </div>
    </div>
  </div>

  <script>
    const envId = window.__sandboxEnvId;
    const syncKey = "ollie_kanban_board_state";

    const teamMembers = [
      {
        key: "mirjam",
        name: "Mirjam van Esch",
        email: "mirjamvanesch@google.com",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXTBbC9f6t0nk1AnwJs5rlbhjpfVQxK2sM8PqQXbNVAx3YKh4LMVA=s64"
      },
      {
        key: "belinda",
        name: "Belinda Preno",
        email: "belindapreno@google.com",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW8kkayF4FN3ib50ZpJsNFIMcSF9CLOgEcXNjlG9yhQ2xy1dL2q=s64"
      },
      {
        key: "simon",
        name: "Simon Sok",
        email: "simonsok@google.com",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjUJwa8yeHprZ88_pXXGVlN6TT1mDyU1T8GUcNOixdQ46wyCNDlcGA=s64"
      },
      {
        key: "ian",
        name: "Ian Mendiola",
        email: "ianmendiola@google.com",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjUP0nZZSsC7tRQg_3si0rRn-TJyMoD8j0kfQm3I-HdLEIVQYBsG=s64"
      }
    ];

    const initialTasks = [
      {
        id: "task-1",
        title: "Complete in-person UXR co-design sessions with Workspace Customers",
        status: "todo",
        assignee: "mirjam"
      },
      {
        id: "task-2",
        title: "Refine Project Ollie UI/UX for main stream and custom views",
        status: "in-progress",
        assignee: "simon"
      },
      {
        id: "task-3",
        title: "Analyze survey responses from 100 participants regarding AI delegation",
        status: "done",
        assignee: "mirjam"
      },
      {
        id: "task-4",
        title: "Build walkthrough and coding agent features for testing",
        status: "todo",
        assignee: "ian"
      },
      {
        id: "task-5",
        title: "Audit and follow up on data privacy requirements for Directors+",
        status: "in-progress",
        assignee: "belinda"
      }
    ];

    let tasks = [...initialTasks];

    if (window.__sandboxWorkspaceName) {
      document.getElementById("board-title").textContent = `${window.__sandboxWorkspaceName} Board`;
    }

    async function loadSyncedState() {
      if (!envId) {
        render();
        return;
      }
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && Array.isArray(json.data)) {
          if (JSON.stringify(tasks) !== JSON.stringify(json.data)) {
            tasks = json.data;
            render();
          }
        } else {
          await saveSyncedState(initialTasks);
          render();
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
        render();
      }
    }

    async function saveSyncedState(newState) {
      if (!envId) {
        tasks = newState;
        render();
        return;
      }
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
        tasks = newState;
        render();
      } catch (err) {
        console.error("Failed to save synced state:", err);
      }
    }

    function render() {
      const todoList = document.getElementById("todo-list");
      const inprogressList = document.getElementById("inprogress-list");
      const doneList = document.getElementById("done-list");

      todoList.innerHTML = "";
      inprogressList.innerHTML = "";
      doneList.innerHTML = "";

      let todoCount = 0;
      let inprogressCount = 0;
      let doneCount = 0;

      tasks.forEach(task => {
        const member = teamMembers.find(m => m.key === task.assignee);
        const card = document.createElement("div");
        card.className = "bg-white p-4 rounded-lg border border-gray-200 hover:border-gray-300 transition-all shadow-sm relative group cursor-grab active:cursor-grabbing";
        card.setAttribute("draggable", "true");
        card.setAttribute("id", task.id);
        card.addEventListener("dragstart", dragStart);

        let assigneeHTML = `
          <div class="flex items-center mt-3 text-xs text-gray-400 italic">
            <span>Unassigned</span>
          </div>
        `;

        if (member) {
          assigneeHTML = `
            <div class="flex items-center mt-3 text-xs text-gray-500">
              <img src="${member.avatar}" alt="${member.name}" class="w-5 h-5 rounded-full mr-2 object-cover" />
              <span>${member.name}</span>
            </div>
          `;
        }

        const moveButtons = getMoveControls(task);

        card.innerHTML = `
          <div class="flex justify-between items-start gap-2">
            <p class="text-sm font-medium text-gray-900 leading-relaxed">${escapeHTML(task.title)}</p>
            <button onclick="deleteTask('${task.id}')" class="text-gray-400 hover:text-red-500 transition opacity-0 group-hover:opacity-100 p-0.5" title="Delete Task">
              <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
            </button>
          </div>
          <div class="flex justify-between items-end">
            ${assigneeHTML}
            ${moveButtons}
          </div>
        `;

        if (task.status === "todo") {
          todoList.appendChild(card);
          todoCount++;
        } else if (task.status === "in-progress") {
          inprogressList.appendChild(card);
          inprogressCount++;
        } else if (task.status === "done") {
          doneList.appendChild(card);
          doneCount++;
        }
      });

      document.getElementById("todo-count").textContent = todoCount;
      document.getElementById("inprogress-count").textContent = inprogressCount;
      document.getElementById("done-count").textContent = doneCount;
    }

    function getMoveControls(task) {
      let leftBtn = "";
      let rightBtn = "";

      if (task.status === "in-progress") {
        leftBtn = `<button onclick="moveTask('${task.id}', 'todo')" class="p-1 text-gray-400 hover:text-blue-600 hover:bg-gray-100 rounded transition" title="Move to To Do">←</button>`;
        rightBtn = `<button onclick="moveTask('${task.id}', 'done')" class="p-1 text-gray-400 hover:text-blue-600 hover:bg-gray-100 rounded transition" title="Move to Done">→</button>`;
      } else if (task.status === "todo") {
        rightBtn = `<button onclick="moveTask('${task.id}', 'in-progress')" class="p-1 text-gray-400 hover:text-blue-600 hover:bg-gray-100 rounded transition" title="Move to In Progress">→</button>`;
      } else if (task.status === "done") {
        leftBtn = `<button onclick="moveTask('${task.id}', 'in-progress')" class="p-1 text-gray-400 hover:text-blue-600 hover:bg-gray-100 rounded transition" title="Move to In Progress">←</button>`;
      }

      return `<div class="flex items-center space-x-1 ml-auto mt-2">${leftBtn}${rightBtn}</div>`;
    }

    function escapeHTML(str) {
      return str.replace(/[&<>'"]/g, 
        tag => ({
          '&': '&amp;',
          '<': '&lt;',
          '>': '&gt;',
          "'": '&#39;',
          '"': '&quot;'
        }[tag] || tag)
      );
    }

    function dragStart(e) {
      e.dataTransfer.setData("text/plain", e.target.id);
    }

    function allowDrop(e) {
      e.preventDefault();
    }

    function drop(e, status) {
      e.preventDefault();
      const id = e.dataTransfer.getData("text/plain");
      moveTask(id, status);
    }

    async function moveTask(id, newStatus) {
      const updated = tasks.map(task => {
        if (task.id === id) {
          return { ...task, status: newStatus };
        }
        return task;
      });
      await saveSyncedState(updated);
    }

    async function deleteTask(id) {
      const updated = tasks.filter(task => task.id !== id);
      await saveSyncedState(updated);
    }

    document.getElementById("add-task-form").addEventListener("submit", async (e) => {
      e.preventDefault();
      const titleInput = document.getElementById("task-title");
      const assigneeInput = document.getElementById("task-assignee");

      const title = titleInput.value.trim();
      const assignee = assigneeInput.value;

      if (!title) return;

      const newTask = {
        id: `task-${Date.now()}`,
        title,
        status: "todo",
        assignee: assignee && assignee !== "unassigned" ? assignee : ""
      };

      const updated = [newTask, ...tasks];
      await saveSyncedState(updated);

      titleInput.value = "";
      assigneeInput.value = "";
    });

    if (envId) {
      loadSyncedState();
      setInterval(loadSyncedState, 2000);
    } else {
      render();
    }
  </script>
</body>
</html>
